38	static int consume_one(void *priv_, char *s, unsigned long size)
39	{
40		struct xdiff_emit_state *priv = priv_;
41		char *ep;
42		while (size) {
43			unsigned long this_size;
44			int ret;
45			ep = memchr(s, '\n', size);
46			this_size = (ep == NULL) ? size : (ep - s + 1);
47			ret = priv->line_fn(priv->consume_callback_data, s, this_size);
48			if (ret)
49				return ret;
50			size -= this_size;
51			s += this_size;
